enum YseStatus {
  YSE_OK(0),
  YSE_ERR_GENERIC(1),
  YSE_ERR_NOT_INITIALIZED(2),
  YSE_ERR_INVALID_HANDLE(3),
  YSE_ERR_INVALID_ARGUMENT(4),
  YSE_ERR_FILE_NOT_FOUND(5),
  YSE_ERR_AUDIO_DEVICE(6),
  YSE_ERR_MIDI(7),
  YSE_ERR_EXCEPTION(8);

  final int value;
  const YseStatus(this.value);

  static YseStatus fromValue(int value) => switch (value) {
    0 => YSE_OK,
    1 => YSE_ERR_GENERIC,
    2 => YSE_ERR_NOT_INITIALIZED,
    3 => YSE_ERR_INVALID_HANDLE,
    4 => YSE_ERR_INVALID_ARGUMENT,
    5 => YSE_ERR_FILE_NOT_FOUND,
    6 => YSE_ERR_AUDIO_DEVICE,
    7 => YSE_ERR_MIDI,
